from collections import deque

def bfs(graph, start):
    seen = {start}
    order = []
    q = deque([start])
    while q:
        node = q.popleft()
        order.append(node)
        for nxt in graph[node]:
            if nxt not in seen:
                seen.add(nxt)
                q.append(nxt)
    return order

def dfs(graph, start):
    seen = set()
    order = []

    def visit(node):
        if node in seen:
            return
        seen.add(node)
        order.append(node)
        for nxt in graph[node]:
            visit(nxt)

    visit(start)
    return order

import heapq

def dijkstra(graph, source):
    dist = {source: 0}
    pq = [(0, source)]
    while pq:
        cost, node = heapq.heappop(pq)
        if cost != dist[node]:
            continue
        for nxt, weight in graph[node]:
            new_cost = cost + weight
            if new_cost < dist.get(nxt, float('inf')):
                dist[nxt] = new_cost
                heapq.heappush(pq, (new_cost, nxt))
    return dist

def solve_sudoku(board):
    digits = set('123456789')

    def choices(row, col):
        used = set(board[row])
        used |= {board[r][col] for r in range(9)}
        box_r, box_c = 3 * (row // 3), 3 * (col // 3)
        used |= {board[r][c] for r in range(box_r, box_r + 3) for c in range(box_c, box_c + 3)}
        return digits - used

    empty = [(r, c) for r in range(9) for c in range(9) if board[r][c] == '.']
    if not empty:
        return True
    row, col = min(empty, key=lambda cell: len(choices(*cell)))
    for value in choices(row, col):
        board[row][col] = value
        if solve_sudoku(board):
            return True
        board[row][col] = '.'
    return False

from collections import deque

def shortest_path(start, goal, neighbors):
    parent = {start: None}
    q = deque([start])
    while q:
        node = q.popleft()
        if node == goal:
            path = []
            while node is not None:
                path.append(node)
                node = parent[node]
            return path[::-1]
        for nxt in neighbors(node):
            if nxt not in parent:
                parent[nxt] = node
                q.append(nxt)
    return None

import heapq

def astar(start, goal, neighbors, heuristic):
    open_set = [(heuristic(start), 0, start, None)]
    parent = {}
    best = {start: 0}
    while open_set:
        _, cost, node, prev = heapq.heappop(open_set)
        if node in parent:
            continue
        parent[node] = prev
        if node == goal:
            path = []
            while node is not None:
                path.append(node)
                node = parent[node]
            return path[::-1]
        for nxt, step_cost in neighbors(node):
            new_cost = cost + step_cost
            if new_cost < best.get(nxt, float('inf')):
                best[nxt] = new_cost
                heapq.heappush(open_set, (new_cost + heuristic(nxt), new_cost, nxt, node))
    return None

def ida_star(start, is_goal, neighbors, heuristic):
    def search(path, g, bound):
        node = path[-1]
        f = g + heuristic(node)
        if f > bound:
            return f
        if is_goal(node):
            return path[:]
        minimum = float('inf')
        for nxt, cost in neighbors(node):
            if nxt in path:
                continue
            path.append(nxt)
            result = search(path, g + cost, bound)
            if isinstance(result, list):
                return result
            minimum = min(minimum, result)
            path.pop()
        return minimum

    bound = heuristic(start)
    path = [start]
    while True:
        result = search(path, 0, bound)
        if isinstance(result, list):
            return result
        if result == float('inf'):
            return None
        bound = result

def beam_search(start, expand, score, width=3, depth_limit=20):
    # expand(node) returns candidate next states.
    # score(node) should be larger for better states.
    beam = [start]
    for _ in range(depth_limit):
        candidates = []
        for node in beam:
            candidates.extend(expand(node))
        if not candidates:
            break
        beam = sorted(candidates, key=score, reverse=True)[:width]
    return beam

