from collections import Counter

def huffman_codes(text):
    heap = [[freq, [char, '']] for char, freq in Counter(text).items()]
    heapq.heapify(heap)
    while len(heap) > 1:
        lo = heapq.heappop(heap)
        hi = heapq.heappop(heap)
        for pair in lo[1:]:
            pair[1] = '0' + pair[1]
        for pair in hi[1:]:
            pair[1] = '1' + pair[1]
        heapq.heappush(heap, [lo[0] + hi[0], *lo[1:], *hi[1:]])
    return dict(heap[0][1:]) if heap else {}

class DSU:
    def __init__(self, n):
        self.parent = list(range(n))
    def find(self, x):
        while self.parent[x] != x:
            self.parent[x] = self.parent[self.parent[x]]
            x = self.parent[x]
        return x
    def union(self, a, b):
        ra, rb = self.find(a), self.find(b)
        if ra == rb:
            return False
        self.parent[rb] = ra
        return True

def kruskal(n, edges):
    dsu = DSU(n)
    tree = []
    for weight, u, v in sorted(edges):
        if dsu.union(u, v):
            tree.append((u, v, weight))
    return tree

def activity_selection(intervals):
    # intervals are (start, finish) pairs
    chosen = []
    current_finish = float('-inf')
    for start, finish in sorted(intervals, key=lambda item: item[1]):
        if start >= current_finish:
            chosen.append((start, finish))
            current_finish = finish
    return chosen

def knapsack(values, weights, capacity):
    dp = [0] * (capacity + 1)
    for value, weight in zip(values, weights):
        for cap in range(capacity, weight - 1, -1):
            dp[cap] = max(dp[cap], dp[cap - weight] + value)
    return dp[capacity]

def lcs(a, b):
    dp = [[0] * (len(b) + 1) for _ in range(len(a) + 1)]
    for i, ca in enumerate(a, 1):
        for j, cb in enumerate(b, 1):
            if ca == cb:
                dp[i][j] = dp[i - 1][j - 1] + 1
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])
    return dp[-1][-1]

def edit_distance(a, b):
    dp = [[0] * (len(b) + 1) for _ in range(len(a) + 1)]
    for i in range(len(a) + 1):
        dp[i][0] = i
    for j in range(len(b) + 1):
        dp[0][j] = j
    for i, ca in enumerate(a, 1):
        for j, cb in enumerate(b, 1):
            cost = 0 if ca == cb else 1
            dp[i][j] = min(
                dp[i - 1][j] + 1,
                dp[i][j - 1] + 1,
                dp[i - 1][j - 1] + cost,
            )
    return dp[-1][-1]

from collections import deque

class Dinic:
    def __init__(self, n):
        self.n = n
        self.adj = [[] for _ in range(n)]
    def add_edge(self, u, v, c):
        self.adj[u].append([v, c, len(self.adj[v])])
        self.adj[v].append([u, 0, len(self.adj[u])-1])
    def maxflow(self, s, t):
        flow = 0
        INF = 10**18
        while True:
            level = [-1]*self.n
            q = deque([s]); level[s] = 0
            while q:
                u = q.popleft()
                for v, cap, rev in self.adj[u]:
                    if cap > 0 and level[v] < 0:
                        level[v] = level[u]+1; q.append(v)
            if level[t] < 0: break
            it = [0]*self.n
            def dfs(u, f):
                if u == t: return f
                for i in range(it[u], len(self.adj[u])):
                    it[u] = i
                    v, cap, rev = self.adj[u][i]
                    if cap > 0 and level[u] < level[v]:
                        d = dfs(v, min(f, cap))
                        if d:  # augment
                            self.adj[u][i][1] -= d
                            self.adj[v][rev][1] += d
                            return d
                return 0
            while True:
                pushed = dfs(s, INF)
                if not pushed: break
                flow += pushed
        return flow

